type EmitterEvents = {
    [key: string]: (...args: any[]) => void;
};

declare class TypedEventEmitter<T extends EmitterEvents> {
    private eventEmitter;
    constructor();
    emit(event: keyof T, ...args: Parameters<T[keyof T]>): void;
    on(event: keyof T, listener: T[keyof T]): void;
    off(event: keyof T, listener: T[keyof T]): void;
    removeAllListeners(event: keyof T): void;
    setMaxListeners(n: number): void;
}

type ApplicationInfo = {
    appID: string;
    interfaceRevision: number;
};
type Effect = {
    id: string;
    isEnabled: boolean;
};
type Input = {
    id: string;
    name?: string;
    isMuted: boolean;
    gain: {
        value: number;
    };
    micPcMix: {
        value: number;
    };
    dspEffects: Effect[];
    effects: Effect[];
};
type InputDevice = {
    id: string;
    name: string;
    isWaveDevice: boolean;
    inputs: Input[];
};
type Output = {
    id: string;
    name: string;
    isMuted: boolean;
    level: number;
    mixId: string;
};
type OutputDevice = {
    id: string;
    name: string;
    isWaveDevice: boolean;
    outputs: Output[];
};
type MainOutput = {
    outputDeviceId: string;
    outputId?: string;
};
type ChannelMix = {
    id: string;
    isMuted: boolean;
    level: number;
};
type Channel = {
    id: string;
    name: string;
    type: string;
    isMuted: boolean;
    level: number;
    mixes: ChannelMix[];
    effects: Effect[];
    apps?: {
        id: string;
        name?: string;
    }[];
};
type Mix = {
    id: string;
    name: string;
    isMuted: boolean;
    level: number;
    image?: {
        name: string;
    };
};
type LevelMeter = {
    id: string;
    subId?: string;
    levelLeftPercentage: number;
    levelRightPercentage: number;
};
type LevelMeters = {
    inputDevices: LevelMeter[];
    outputDevices: LevelMeter[];
    channels: LevelMeter[];
    mixes: LevelMeter[];
};
type FocusedApp = {
    id: string;
    name: string;
    channel: {
        id: string;
    };
};
type SubscriptionType = 'input' | 'output' | 'channel' | 'mix';
type SubscriptionPayload = {
    isEnabled: boolean;
    type?: SubscriptionType;
    id?: string;
    subId?: string;
};
type WaveLinkControllerEvents = {
    ready: () => void;
    disconnected: () => void;
    inputDevicesChanged: () => void;
    inputDeviceChanged: (id: string) => void;
    outputDevicesChanged: () => void;
    outputDeviceChanged: (id: string) => void;
    mainOutputDeviceChanged: (mainOutput: MainOutput) => void;
    channelsChanged: () => void;
    channelChanged: (id: string, mixIds: string[], changedProperties: string[]) => void;
    mixesChanged: () => void;
    mixChanged: (id: string) => void;
    levelMeterChanged: () => void;
    focusedAppChanged: (app: FocusedApp) => void;
};
/**
 * setInputDevice payload.
 * Wrap changes inside inputs[]. Only provide the fields you want to change.
 */
type SetInputDevicePayload = {
    id: string;
    inputs: Array<{
        id: string;
        isMuted?: boolean;
        gain?: {
            value: number;
        };
        micPcMix?: {
            value: number;
        };
        effects?: Array<{
            id: string;
            isEnabled: boolean;
        }>;
        dspEffects?: Array<{
            id: string;
            isEnabled: boolean;
        }>;
    }>;
};
/**
 * setOutputDevice has two overloaded forms:
 * 1. Modify outputs on a device (level, mute, mixId assignment)
 * 2. Set the main output
 */
type SetOutputDevicePayload = {
    outputDevice: {
        id: string;
        outputs: Array<{
            id: string;
            isMuted?: boolean;
            level?: number;
            mixId?: string;
        }>;
    };
} | {
    mainOutput: MainOutput;
};
/**
 * setChannel payload.
 * All fields except id are optional — only send what you want to change.
 */
type SetChannelPayload = {
    id: string;
    level?: number;
    isMuted?: boolean;
    mixes?: Array<{
        id: string;
        level?: number;
        isMuted?: boolean;
    }>;
    effects?: Array<{
        id: string;
        isEnabled: boolean;
    }>;
};
/**
 * setMix payload.
 */
type SetMixPayload = {
    id: string;
    level?: number;
    isMuted?: boolean;
};

